(77, 'LIB-00035-0526', 'Project 1. Survey on the Food Environment Towards Sustainable Food Production and Consumption (SARI)', 'T2025-01', '07', 'NAMD', '1 year', 'BS-Rosefil', 1, 0, 0, '', '', '2025-05-26 06:07:28', 'BS-Rosefil', 'TOWARDS A SUSTAINABLE PHILIPPINE FOOD SYSTEM: UNDERSTANDING AVAILABILITY, ACCESSIBILITY, LIVED EXPERIENCES AND NUTRITION OUTCOMES THROUGH MAPPING AND MODELING GEOSPATIAL AND OBSERVATIONAL DATA (PALIGID)', 'Two (2) Years', '2024-12-16', '2025-12-15', 'DR. MILDRED O. GUIRINDOLA', 'PHILIPPINE COUNCIL FOR INDUSTRY, ENERGY AND EMERGING TECHNOLOGY RESEARCH AND DEVELOPMENT (PCIEERD)', 'Alliance Bioversity International and CIAT-ASIA; Department of Agriculture; Department of Health-Health Promotion Bureau; UP Diliman-Training Center for Applied Geodesy; National Nutrition Council (NNC); Healthy Philippines Alliance; LGU Baguio City; Biliran; Sultan Kudarat; DOST-PAGASA; DOST-PHILVOCS', 'Food and Nutrition Research Institute (FNRI)', 'Department of Science and Technology (DOST)', 'Save to Draft', 0, 0, 0, 0, '0000-00-00', '0000-00-00', '01'),
